mapper.select:
SELECT (
    COALESCE((
        SELECT COUNT(*)
        FROM supplier_book_value_inventory
        WHERE sku = #{itemCode}
          AND store = #{storeCode}
          AND (closing_qty <> 0 OR unbill_qty <> 0)
    ), 0)
    + COALESCE((
        SELECT COUNT(*)
        FROM customer_consignment_inventory
        WHERE sku = #{itemCode}
          AND issue_from_store = #{storeCode}
          AND qty <> 0
    ), 0)
    + COALESCE((
        SELECT COUNT(*)
        FROM unpost_staging_inventory
        WHERE sku = #{itemCode}
          AND location = #{storeCode}
          AND (sales_qty <> 0 OR return_qty <> 0)
    ), 0)
    + COALESCE((
        SELECT COUNT(*)
        FROM consignment_reservation
        WHERE sku = #{itemCode}
          AND store = #{storeCode}
          AND qty <> 0
    ), 0)
)
